const alcoholRecipes={
 strawberrymargarita:{abv:'5.8',method:{de:'Agavensirup, Limettensaft und Wasser gründlich verrühren. Erdbeernektar, Orangensaft, Tequila, Triple Sec und Salz hinzufügen, vollständig vorkühlen und im Spiked-Slush-Programm verarbeiten. Für das Finish einen Zucker-Salz-Rand sowie Erdbeere und Limette verwenden.',en:'Whisk the agave syrup, lime juice and water together. Add the strawberry nectar, orange juice, tequila, triple sec and salt, chill thoroughly and process on Spiked Slush. Finish with a sugar-and-salt rim, strawberry and lime.'}},
 pinacolada:{abv:'4.9',method:{de:'Kokosmilch homogen rühren, dann Kokossirup, Wasser und Limettensaft einarbeiten. Ananassaft, Rum und Salz hinzufügen, sehr kalt im Spiked-Slush-Programm verarbeiten. Kokosflocken ausschließlich als Garnitur verwenden.',en:'Whisk the coconut milk until uniform, then mix in the coconut syrup, water and lime juice. Add the pineapple juice, rum and salt and process very cold on Spiked Slush. Use coconut flakes only as a garnish.'}},
 peachbellini:{abv:'5.0',method:{de:'Pfirsichnektar, Wasser, Zitronensaft, Likör und Zuckersirup verrühren. Prosecco langsam hinzugeben und den Schaum abklingen lassen. Gut gekühlt im Spiked-Slush-Programm verarbeiten und mit einer dünnen Pfirsichscheibe servieren.',en:'Mix the peach nectar, water, lemon juice, liqueur and simple syrup. Slowly add the prosecco and allow the foam to settle. Process well chilled on Spiked Slush and serve with a thin peach slice.'}},
 berryfrose:{abv:'6.6',method:{de:'Zuckersirup, Zitronensaft und Wasser verrühren. Beerensaft und Erdbeernektar hinzufügen, Rosé langsam einrühren und gut vorkühlen. Im Spiked-Slush-Programm verarbeiten und mit frischen Beeren servieren.',en:'Mix the simple syrup, lemon juice and water. Add the berry juice and strawberry nectar, slowly stir in the rosé and chill thoroughly. Process on Spiked Slush and serve with fresh berries.'}},
 passionmojito:{abv:'4.9',method:{de:'Limettensaft mit Minz- und Rohrzuckersirup verrühren. Maracujanektar und Kokoswasser hinzufügen, zuletzt den Rum einrühren. Sehr kalt im Spiked-Slush-Programm verarbeiten. Minzblätter nur als Garnitur verwenden.',en:'Mix the lime juice with the mint and cane syrups. Add the passion fruit nectar and coconut water, then stir in the rum last. Process very cold on Spiked Slush. Use mint leaves only as a garnish.'}},
 irishchocolate:{abv:'2.6',method:{de:'Kakao und Zucker mit etwa 100 ml Milch klümpchenfrei verrühren. Restliche Milch, Sahne, Schokoladensirup, Vanille und Salz hinzufügen, Irish Cream zuletzt einrühren. Vollständig vorkühlen und im Milkshake-Programm verarbeiten.',en:'Whisk the cocoa and sugar with about 100 ml milk until smooth. Add the remaining milk, cream, chocolate syrup, vanilla and salt, then stir in the Irish cream last. Chill thoroughly and process on Milkshake.'}},
 bourboncaramel:{abv:'4.1',method:{de:'Braunen Zucker und Salz in einem Teil der Milch vollständig auflösen. Restliche Milch, Sahne, Karamellsirup und Vanille einrühren, dann Bourbon hinzufügen. Vorkühlen und im Milkshake-Programm verarbeiten.',en:'Completely dissolve the brown sugar and salt in part of the milk. Stir in the remaining milk, cream, caramel syrup and vanilla, then add the bourbon. Chill and process on Milkshake.'}},
 bananarum:{abv:'4.4',method:{de:'Braunen Zucker in einem Teil der Milch auflösen. Bananennektar, restliche Milch, Sahne und Karamellsirup einrühren. Rum, Vanille, Zimt und Salz hinzufügen, sehr kalt im Milkshake-Programm verarbeiten.',en:'Dissolve the brown sugar in part of the milk. Stir in the banana nectar, remaining milk, cream and caramel syrup. Add the rum, vanilla, cinnamon and salt and process very cold on Milkshake.'}},
 amarettocherry:{abv:'3.4',method:{de:'Milch, Sahne, Kirschsirup und Vanillesirup verrühren. Amaretto und Salz hinzufügen, gut vorkühlen und im Milkshake-Programm verarbeiten. Nach Erreichen der Konsistenz direkt ausschenken.',en:'Mix the milk, cream, cherry syrup and vanilla syrup. Add the amaretto and salt, chill thoroughly and process on Milkshake. Serve as soon as the desired consistency is reached.'}},
 espressomartini:{abv:'5.1',method:{de:'Espresso vollständig abkühlen lassen und mit Kaffeesirup, Vanille und Salz verrühren. Milch und Sahne hinzufügen, Wodka und Kaffeelikör zuletzt einrühren. Im Milkshake- oder für eine leichtere Konsistenz im Frappé-Programm verarbeiten.',en:'Cool the espresso completely and mix it with the coffee syrup, vanilla and salt. Add the milk and cream, then stir in the vodka and coffee liqueur last. Process on Milkshake, or use Frappé for a lighter texture.'}}
};
