 de:{country:'Land',easy:'Einfach erhältlich',specialty:'Mit Spezialhandel',rare:'Selten/teuer einschließen',available:'Gut erhältlich',specialtyStatus:'Spezialhandel',rareStatus:'Selten/teuer',unavailable:'Nicht verfügbar',restricted:'Eingeschränkt',prohibited:'Verboten',unknown:'Unklare Datenlage',availability:'Verfügbarkeit',local_common:'Regional üblich',import_common:'Regelmäßig importiert',specialtyCode:'Im Spezialhandel',rare_expensive:'Selten oder teuer',unavailableCode:'Nicht regulär verfügbar',restrictedCode:'Rechtlich eingeschränkt',prohibitedCode:'Verboten',unknownCode:'Unbekannt',checked:'Datenstand',recipesVisible:'Rezepte passend',legalPending:'Handelsdatenbasierte Schätzung. Die rechtliche Einzelprüfung für dieses Land steht noch aus.'},
