let lang=localStorage.getItem('slushy-lang')||'de', active='all', limit=9;
let availabilityDb=null,selectedCountry=localStorage.getItem('slushy-country')||'DE',availabilityMode=localStorage.getItem('slushy-availability')||'easy';
const imagePath=id=>`assets/recipes/${id}.webp?v=20260712-3`;
const yieldFor=r=>r[4][lang];
const ingredientsFor=r=>r[6][lang];
const searchableIngredients=r=>[...r[6].de,...r[6].en].join(' ');
const profileMarkup=id=>{const profile=flavorProfiles[id];return `<section class="flavor-profile"><div class="profile-heading"><h3>${copy[lang].flavorProfile}</h3><span>${copy[lang].scaleHint}</span></div>${['sweetness','acidity','creaminess'].map(key=>`<div class="profile-row"><div class="profile-label"><span>${copy[lang][key]}</span><strong>${profile[key]}/10</strong></div><div class="profile-track" role="meter" aria-label="${copy[lang][key]}" aria-valuemin="1" aria-valuemax="10" aria-valuenow="${profile[key]}"><i style="--score:${profile[key]}"></i></div></div>`).join('')}</section>`};
const allergenMarkup=id=>{const data=recipeAllergens[id]||{},c=allergenCopy[lang],group=(label,keys,type)=>keys?.length?`<div class="allergen-group"><strong>${label}</strong><div>${keys.map(key=>`<span class="allergen-chip ${type}">${c[key]}</span>`).join('')}</div></div>`:'';return `<section class="allergen-panel"><h3>${c.title}</h3>${data.contains?.length?'':`<p class="allergen-none">${c.none}</p>`}${group(c.contains,data.contains,'contains')}${group(c.conditional,data.conditional,'conditional')}${group(c.other,data.other,'other')}<div class="allergen-notes">${(data.notes||[]).map(key=>`<p>${c[key]}</p>`).join('')}<p>${c.check}</p><p>${c.crossContact}</p></div></section>`};
const statusOrder={local_common:0,import_common:0,specialty:1,rare_expensive:2,unknown:3,unavailable:4,restricted:5,prohibited:6};
function ingredientStatus(key){if(!availabilityDb)return 'unknown';const country=availabilityDb.countries[selectedCountry];for(const status of Object.keys(statusOrder)){if(country[status]?.includes(key))return status}return 'unknown'}
function recipeAvailability(id){const keys=availabilityDb?.recipes[id]||[];const items=keys.map(key=>({key,status:ingredientStatus(key)}));const worst=items.reduce((a,b)=>statusOrder[b.status]>statusOrder[a]?b.status:a,'local_common');return {worst,items}}
function availabilityLabel(status){const c=availabilityCopy[lang];return status==='local_common'||status==='import_common'?c.available:status==='specialty'?c.specialtyStatus:status==='rare_expensive'?c.rareStatus:status==='restricted'?c.restricted:status==='prohibited'?c.prohibited:status==='unavailable'?c.unavailable:c.unknown}
function recipeAllowed(id){if(!availabilityDb)return true;const score=statusOrder[recipeAvailability(id).worst],ceiling=availabilityMode==='easy'?0:availabilityMode==='specialty'?1:2;return score<=ceiling}
function availabilityBadge(id){if(!availabilityDb)return '';const status=recipeAvailability(id).worst;return `<span class="availability-badge status-${status}">${availabilityLabel(status)}</span>`}
function countryName(code,data){try{return new Intl.DisplayNames([lang],{type:'region'}).of(code)||data.name[lang]}catch{return data.name[lang]}}
function availabilityDetails(id){if(!availabilityDb)return '';const result=recipeAvailability(id),db=availabilityDb,c=availabilityCopy[lang],country=db.countries[selectedCountry],pending=country.legalReview==='pending';return `<section class="availability-detail"><div class="availability-title"><div><h3>${c.availability}</h3><p>${countryName(selectedCountry,country)} · ${c.checked}: ${db.checkedAt}</p></div>${availabilityBadge(id)}</div>${pending?`<p class="legal-pending">${c.legalPending}</p>`:''}<ul>${result.items.map(item=>{const ingredient=db.ingredients[item.key],evidence=db.evidence?.[`${selectedCountry}:${item.key}`],label=item.status==='specialty'?c.specialtyCode:item.status==='unavailable'?c.unavailableCode:item.status==='restricted'?c.restrictedCode:item.status==='prohibited'?c.prohibitedCode:item.status==='unknown'?c.unknownCode:c[item.status];return `<li><span>${ingredient?.[lang]||item.key}</span><strong class="status-text-${item.status}">${label}</strong>${evidence?`<small>${evidence.note[lang]} ${evidence.metric?`(${evidence.metric})`:''}</small>`:''}</li>`}).join('')}</ul></section>`}
const alcoholBadge=id=>alcoholRecipes[id]?`<span class="alcohol-badge">${alcoholCopy[lang].badge}</span>`:'';
const methodFor=id=>alcoholRecipes[id]?.method[lang]||copy[lang].methodText;
function alcoholSafetyMarkup(id){const data=alcoholRecipes[id];if(!data)return '';const c=alcoholCopy[lang];return `<section class="alcohol-safety"><div class="alcohol-safety-title"><span>ALC</span><div><h3>${c.title}</h3><strong>${c.estimated}: ${data.abv.replace('.',lang==='de'?',':'.')} % vol</strong></div></div><p>${c.servings}</p><p>${c.legal}</p><p>${c.warning}</p><small>${c.estimate}</small></section>`}
let pendingAlcoholRecipe=null;
function requestAlcoholAccess(id){pendingAlcoholRecipe=id;const c=alcoholCopy[lang],dialog=document.querySelector('#ageDialog');dialog.querySelector('h2').textContent=c.gateTitle;dialog.querySelector('.age-gate-text').textContent=c.gateText;dialog.querySelector('.age-check-text').textContent=c.gateCheck;dialog.querySelector('.age-enter').textContent=c.enter;dialog.querySelector('.age-cancel').textContent=c.cancel;dialog.querySelector('input').checked=false;dialog.showModal()}
function hasAlcoholAccess(){return sessionStorage.getItem('slushy-alcohol-age-confirmed')==='yes'}
async function loadAvailability(){try{const response=await fetch('data/availability.json?v=20260712-2');if(!response.ok)throw new Error(response.status);availabilityDb=await response.json();if(!availabilityDb.countries[selectedCountry])selectedCountry='DE'}catch(error){console.warn('Availability data could not be loaded',error)}}
const grid=document.querySelector('#recipeGrid'), filters=document.querySelector('#filters');
function paint(){document.documentElement.lang=lang;document.querySelectorAll('[data-i18n]').forEach(el=>{if(copy[lang][el.dataset.i18n])el.textContent=copy[lang][el.dataset.i18n]});document.querySelector('#recipeCount').textContent=recipes.length;document.querySelector('#search').placeholder=document.querySelector('#search').dataset[`placeholder${lang==='de'?'De':'En'}`];document.querySelectorAll('[data-lang]').forEach(b=>b.classList.toggle('active',b.dataset.lang===lang));renderFilters();renderAvailabilityControls();render();}
function renderAvailabilityControls(){if(!availabilityDb)return;const c=availabilityCopy[lang],select=document.querySelector('#country');document.querySelector('.country-control label').textContent=c.country;select.innerHTML=Object.entries(availabilityDb.countries).sort((a,b)=>countryName(a[0],a[1]).localeCompare(countryName(b[0],b[1]),lang)).map(([code,data])=>`<option value="${code}" ${code===selectedCountry?'selected':''}>${countryName(code,data)}</option>`).join('');document.querySelector('#availabilityModes').innerHTML=['easy','specialty','rare'].map(mode=>`<button class="filter ${availabilityMode===mode?'active':''}" data-mode="${mode}">${c[mode]}</button>`).join('');select.onchange=()=>{selectedCountry=select.value;localStorage.setItem('slushy-country',selectedCountry);limit=9;paint()};document.querySelectorAll('[data-mode]').forEach(button=>button.onclick=()=>{availabilityMode=button.dataset.mode;localStorage.setItem('slushy-availability',availabilityMode);limit=9;paint()})}
function renderFilters(){filters.innerHTML=['all','fruit','cocktail','creamy','vegan','seasonal','indonesia','alcohol'].map(x=>`<button class="filter ${x===active?'active':''}" data-filter="${x}">${copy[lang][x]}</button>`).join('');filters.querySelectorAll('button').forEach(b=>b.onclick=()=>{active=b.dataset.filter;limit=9;paint()})}
function render(){const q=document.querySelector('#search').value.toLowerCase();const list=recipes.filter(r=>(active==='all'||r[3]===active||(active==='indonesia'&&indonesiaIds.has(r[0])))&&recipeAllowed(r[0])&&`${r[1]} ${r[2]} ${searchableIngredients(r)}`.toLowerCase().includes(q));grid.innerHTML=list.length?list.slice(0,limit).map(r=>{const c=palette[r[0]],name=lang==='de'?r[1]:r[2];return `<article class="recipe-card ${r[3]==='alcohol'?'alcohol-card':''}" tabindex="0" data-id="${r[0]}"><div class="recipe-visual" style="--visual:linear-gradient(145deg,${c[0]},${c[1]})"><img src="${imagePath(r[0])}" alt="${name}" loading="lazy" onerror="this.remove()">${availabilityBadge(r[0])}${alcoholBadge(r[0])}</div><div class="card-body"><div class="card-meta"><span>${copy[lang][r[3]]}</span><span>${yieldFor(r)}</span></div><h3>${name}</h3><div class="card-stats"><span>❄ ${r[5]}</span><span>◷ 30–60 min</span></div></div></article>`}).join(''):`<p>${copy[lang].result}</p>`;document.querySelector('#availabilitySummary').textContent=availabilityDb?`${list.length} ${availabilityCopy[lang].recipesVisible}`:'';document.querySelector('#loadMore').hidden=list.length<=limit;grid.querySelectorAll('.recipe-card').forEach(card=>{card.onclick=()=>openRecipe(card.dataset.id);card.onkeydown=e=>{if(e.key==='Enter')openRecipe(card.dataset.id)}})}
function openRecipe(id){if(alcoholRecipes[id]&&!hasAlcoholAccess()){requestAlcoholAccess(id);return}const r=recipes.find(x=>x[0]===id),c=palette[id],name=lang==='de'?r[1]:r[2];document.querySelector('#dialogContent').innerHTML=`<div class="dialog-visual" style="--visual:linear-gradient(145deg,${c[0]},${c[1]})"><img src="${imagePath(id)}" alt="${name}" onerror="this.remove()"><span>${copy[lang].looks}</span></div><div class="dialog-body"><p class="eyebrow dark">${copy[lang][r[3]]} · ${yieldFor(r)}</p><div class="recipe-title-row"><h2>${name}</h2><button class="print-recipe" type="button" title="${copy[lang].print}"><span aria-hidden="true">🖨</span>${copy[lang].print}</button></div><p>❄ ${r[5]} &nbsp; ◷ 30–60 min</p>${alcoholSafetyMarkup(id)}${availabilityDetails(id)}${profileMarkup(id)}<h3>${copy[lang].ingredients}</h3><ul class="ingredients">${ingredientsFor(r).map(x=>`<li>${x}</li>`).join('')}</ul>${allergenMarkup(id)}<h3>${copy[lang].method}</h3><p class="steps">${methodFor(id)}</p>${commentSectionMarkup(id)}</div>`;document.querySelector('.print-recipe').onclick=()=>printRecipe(name);document.querySelector('#recipeDialog').showModal();initRecipeComments(id)}
function printRecipe(name){const previousTitle=document.title;document.title=`${name} | SlushyWeb`;const restore=()=>{document.title=previousTitle;window.removeEventListener('afterprint',restore)};window.addEventListener('afterprint',restore);window.print()}
document.querySelectorAll('[data-lang]').forEach(b=>b.onclick=()=>{lang=b.dataset.lang;localStorage.setItem('slushy-lang',lang);paint()});document.querySelector('#search').oninput=render;document.querySelector('#searchFocus').onclick=()=>{location.hash='recipes';setTimeout(()=>document.querySelector('#search').focus(),300)};document.querySelector('#loadMore').onclick=()=>{limit+=9;render()};document.querySelector('.dialog-close').onclick=()=>document.querySelector('#recipeDialog').close();document.querySelector('#recipeDialog').onclick=e=>{if(e.target.id==='recipeDialog')e.currentTarget.close()};loadAvailability().then(paint);
document.querySelector('.age-gate').onsubmit=e=>{e.preventDefault();sessionStorage.setItem('slushy-alcohol-age-confirmed','yes');document.querySelector('#ageDialog').close();const id=pendingAlcoholRecipe;pendingAlcoholRecipe=null;if(id)openRecipe(id)};
document.querySelector('.age-cancel').onclick=()=>{pendingAlcoholRecipe=null;document.querySelector('#ageDialog').close()};
